            backend_req.set_connect_timeout(backend_config.connect_timeout);
            backend_req.set_first_byte_timeout(backend_config.first_byte_timeout);
            backend_req.set_between_bytes_timeout(backend_config.between_bytes_timeout);
            
            // Set SNI if specified
            if let Some(sni) = &backend_config.sni {
                backend_req.set_sni(sni.clone());
            }
            
            // Send request to backend
            let backend_resp = backend_req.send()?;
            
            Ok(backend_resp)
